        const accountInfo = await rpcCall(rpcUrl, "proxy_getAccountInfo", {
          address: senderPubkey,
          token_balances_filter: [],
          state_key_filter: null,
          certificate_by_nonce: null
        });
        const nonce = accountInfo?.next_nonce ?? 0;
