var BASE_URL2 = "https://api.paraswap.io";
var PARASWAP_NATIVE = "0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE";
var ZERO_ADDRESS = "0x0000000000000000000000000000000000000000";
function toParaswapToken(address) {
  if (address.toLowerCase() === ZERO_ADDRESS.toLowerCase()) {
    return PARASWAP_NATIVE;
  }
  return address;
}
var CHAIN_IDS = {
  ethereum: 1,
  optimism: 10,
  bsc: 56,
  polygon: 137,
  base: 8453,
  arbitrum: 42161,
  avalanche: 43114,
  fantom: 250,
  zksync: 324,
  linea: 59144,
  scroll: 534352
};
var SUPPORTED_CHAINS = Object.keys(CHAIN_IDS);
var paraswapProvider = {
  name: "paraswap",
  chains: SUPPORTED_CHAINS,
  async quote(params) {
    const chainId = params.chainId ?? CHAIN_IDS[params.chain];
    if (!chainId) {
      throw new Error(`Paraswap does not support chain "${params.chain}"`);
    }
    const srcToken = toParaswapToken(params.fromToken);
    const destToken = toParaswapToken(params.toToken);
    const url2 = new URL(`${BASE_URL2}/prices`);
    url2.searchParams.set("srcToken", srcToken);
    url2.searchParams.set("srcDecimals", String(params.fromDecimals));
    url2.searchParams.set("destToken", destToken);
    url2.searchParams.set("destDecimals", String(params.toDecimals));
    url2.searchParams.set("amount", params.amount);
    url2.searchParams.set("network", String(chainId));
    url2.searchParams.set("side", "SELL");
    url2.searchParams.set("version", "6.2");
    if (params.userAddress) {
      url2.searchParams.set("userAddress", params.userAddress);
    }
    const res = await fetch(url2.toString());
    if (!res.ok) {
      const text = await res.text();
      throw new Error(`Paraswap quote failed (${res.status}): ${text}`);
    }
    const data = await res.json();
    const pr = data.priceRoute;
    const fromAmountHuman = formatAmount2(pr.srcAmount, pr.srcDecimals);
    const toAmountHuman = formatAmount2(pr.destAmount, pr.destDecimals);
    const priceImpact = "0";
    return {
      fromToken: pr.srcToken,
      toToken: pr.destToken,
      fromAmount: pr.srcAmount,
      toAmount: pr.destAmount,
      fromAmountHuman,
      toAmountHuman,
      priceImpact,
      route: data.priceRoute,
      // pass full priceRoute back for building tx
      provider: "paraswap"
    };
  },
  async swap(params) {
    const chainId = params.chainId ?? CHAIN_IDS[params.chain];
    if (!chainId)
      throw new Error(`Paraswap does not support chain "${params.chain}"`);
    if (!params.evmExecutor)
      throw new Error("Paraswap swap requires evmExecutor");
    const srcToken = toParaswapToken(params.fromToken);
    const destToken = toParaswapToken(params.toToken);
    const buildRes = await fetch(`${BASE_URL2}/transactions/${chainId}?ignoreChecks=true`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        srcToken,
        destToken,
        srcAmount: params.amount,
        priceRoute: params.route,
        userAddress: params.userAddress,
        slippage: params.slippageBps
      })
    });
    if (!buildRes.ok) {
      const text = await buildRes.text();
      throw new Error(`Paraswap build tx failed (${buildRes.status}): ${text}`);
    }
    const txData = await buildRes.json();
    if (srcToken.toLowerCase() !== PARASWAP_NATIVE.toLowerCase()) {
      const spender = txData.to;
      const currentAllowance = await params.evmExecutor.checkAllowance(params.fromToken, spender, params.userAddress);
      if (currentAllowance < BigInt(params.amount)) {
        await params.evmExecutor.approveErc20(params.fromToken, spender, params.amount);
      }
    }
    if (!txData.to)
      throw new Error("Paraswap returned empty transaction target");
    const receipt = await params.evmExecutor.sendTx({
      to: txData.to,
      data: txData.data,
      value: txData.value,
      gas: txData.gas
    });
    if (receipt.status === "reverted") {
      throw new Error(`Paraswap swap transaction reverted: ${receipt.txHash}`);
    }
    return { txHash: receipt.txHash };
  }
};
function formatAmount2(raw, decimals) {
  const num2 = BigInt(raw);
  const divisor = BigInt(10 ** decimals);
  const whole = num2 / divisor;
  const frac = num2 % divisor;
  if (frac === 0n)
    return whole.toString();
  const fracStr = frac.toString().padStart(decimals, "0").replace(/0+$/, "");
  return `${whole}.${fracStr}`;
}

