var BASE_URL4 = "https://dln.debridge.finance/v1.0";
var DEBRIDGE_CHAIN_IDS = {
  ethereum: 1,
  optimism: 10,
  bsc: 56,
  polygon: 137,
  base: 8453,
  arbitrum: 42161,
  avalanche: 43114,
  linea: 59144,
  fantom: 250,
  solana: 7565164
};
var SUPPORTED_CHAINS2 = Object.keys(DEBRIDGE_CHAIN_IDS);
var debridgeProvider = {
  name: "debridge",
  chains: SUPPORTED_CHAINS2,
  async bridge(params) {
    const srcChainId = params.fromChainId ?? DEBRIDGE_CHAIN_IDS[params.fromChain];
    const dstChainId = params.toChainId ?? DEBRIDGE_CHAIN_IDS[params.toChain];
    if (!srcChainId) {
      throw new Error(`DeBridge does not support source chain "${params.fromChain}"`);
    }
    if (!dstChainId) {
      throw new Error(`DeBridge does not support destination chain "${params.toChain}"`);
    }
    const srcToken = params.fromToken;
    const dstToken = params.toToken;
    const url2 = new URL(`${BASE_URL4}/dln/order/create-tx`);
    url2.searchParams.set("srcChainId", String(srcChainId));
    url2.searchParams.set("srcChainTokenIn", srcToken);
    url2.searchParams.set("srcChainTokenInAmount", params.amount);
    url2.searchParams.set("dstChainId", String(dstChainId));
    url2.searchParams.set("dstChainTokenOut", dstToken);
    url2.searchParams.set("dstChainTokenOutRecipient", params.receiverAddress);
    url2.searchParams.set("senderAddress", params.senderAddress);
    url2.searchParams.set("prependOperatingExpenses", "true");
    url2.searchParams.set("dstChainTokenOutAmount", "auto");
    url2.searchParams.set("srcChainOrderAuthorityAddress", params.senderAddress);
    url2.searchParams.set("srcChainRefundAddress", params.senderAddress);
    url2.searchParams.set("dstChainOrderAuthorityAddress", params.receiverAddress);
    const res = await fetch(url2.toString());
    if (!res.ok) {
      const text = await res.text();
      throw new Error(`DeBridge create-tx failed (${res.status}): ${text}`);
    }
    const data = await res.json();
    const isSolanaSource = params.fromChain === "solana";
    let txHash;
    if (isSolanaSource) {
      if (!params.solanaExecutor) {
        throw new Error("DeBridge Solana bridge requires solanaExecutor");
      }
      const txBytes = Buffer.from(data.tx.data, "base64");
      const result = await params.solanaExecutor.signAndSend(new Uint8Array(txBytes));
      if (result.status === "failed") {
        throw new Error(`DeBridge Solana bridge transaction failed: ${result.txHash}`);
      }
      txHash = result.txHash;
    } else {
      if (!params.evmExecutor) {
        throw new Error("DeBridge EVM bridge requires evmExecutor");
      }
      if (!data.tx.to) {
        throw new Error("DeBridge returned empty transaction target. The API response may be incomplete.");
      }
      const isNativeToken = params.fromToken === "0x0000000000000000000000000000000000000000";
      if (!isNativeToken) {
        const requiredAmount = BigInt(data.estimation.srcChainTokenIn.amount);
        const currentAllowance = await params.evmExecutor.checkAllowance(params.fromToken, data.tx.to, params.senderAddress);
        if (currentAllowance < requiredAmount) {
          await params.evmExecutor.approveErc20(params.fromToken, data.tx.to, data.estimation.srcChainTokenIn.amount);
        }
      }
      const receipt = await params.evmExecutor.sendTx({
        to: data.tx.to,
        data: data.tx.data,
        value: data.tx.value
      });
      if (receipt.status === "reverted") {
        throw new Error(`DeBridge bridge transaction reverted: ${receipt.txHash}`);
      }
      txHash = receipt.txHash;
    }
    return {
      txHash,
      orderId: data.orderId ?? txHash,
      estimatedTime: "1-5 minutes"
    };
  }
};

