function getZodTypeName(field) {
  const def = field._def;
  const type = def.type;
  if (type === "optional" && def.innerType)
    return getZodTypeName(def.innerType);
  if (type === "union") {
    const options = def.options;
    if (options)
      return options.map(getZodTypeName).join(" | ");
  }
  if (type === "enum") {
    const entries = def.entries;
    if (entries)
      return Object.keys(entries).map((v) => `"${v}"`).join(" | ");
  }
  if (type === "pipe" && def.in)
    return getZodTypeName(def.in);
  if (type === "custom")
    return "Uint8Array";
  return type ?? "unknown";
}
function getFieldDescription(field) {
  const desc = field.description;
  if (desc)
    return desc;
  const innerType = field._def.innerType;
  return innerType?.description ?? "";
}
function schemaToParamString(schema) {
  const fields = Object.entries(schema.shape).map(([k, v]) => {
    const field = v;
    return field.isOptional() ? `${k}?` : k;
  });
  return `{ ${fields.join(", ")} }`;
}
function schemaToResultString(schema) {
  const fields = Object.entries(schema.shape).map(([k, v]) => {
    const field = v;
    return field.isOptional() ? `${k}?` : k;
  });
  return `{ ${fields.join(", ")} }`;
}
function schemaToParamDetails(schema) {
  const details = {};
  for (const [key, value] of Object.entries(schema.shape)) {
    const field = value;
    const typeName = getZodTypeName(field);
    const desc = getFieldDescription(field);
    const opt = field.isOptional() ? " (optional)" : "";
    details[key] = desc ? `${typeName}${opt} \u2014 ${desc}` : `${typeName}${opt}`;
  }
  return details;
}

